from langchain_core.chat_history import InMemoryChatMessageHistory
from langchain_core.runnables.history import RunnableWithMessageHistory

# Create store
store = {}

def get_session_history(session_id: str):
    if session_id not in store:
        store[session_id] = InMemoryChatMessageHistory()
    return store[session_id]

# Wrap chain with memory
chain_with_memory = RunnableWithMessageHistory(
    chain,
    get_session_history,
    input_messages_key="input",
    history_messages_key="history"
)

# Use with session
result = chain_with_memory.invoke(
    {"input": "My name is Alice"},
    config={"configurable": {"session_id": "user-123"}}
)

# Later in same session
result = chain_with_memory.invoke(
    {"input": "What's my name?"},
    config={"configurable": {"session_id": "user-123"}}
)
# Returns: "Your name is Alice"

from langchain.memory import ConversationSummaryMemory
from langchain_openai import ChatOpenAI

summary_llm = ChatOpenAI(model="gpt-4o-mini")

class SummaryMemory:
    def __init__(self, llm, max_messages: int = 10):
        self.llm = llm
        self.max_messages = max_messages
        self.messages = []
        self.summary = ""

    def add_message(self, role: str, content: str):
        self.messages.append({"role": role, "content": content})

        if len(self.messages) > self.max_messages:
            self._summarize()

    def _summarize(self):
        # Summarize oldest half
        to_summarize = self.messages[:len(self.messages)//2]
        remaining = self.messages[len(self.messages)//2:]

        messages_text = "\n".join(
            f"{m['role']}: {m['content']}" for m in to_summarize
        )

        prompt = f"""Summarize this conversation:
        Previous summary: {self.summary}

        New messages:
        {messages_text}
        """

        response = self.llm.invoke(prompt)
        self.summary = response.content
        self.messages = remaining

    def get_context(self) -> str:
        recent = "\n".join(
            f"{m['role']}: {m['content']}" for m in self.messages
        )
        return f"Summary: {self.summary}\n\nRecent:\n{recent}"

from langchain_openai import OpenAIEmbeddings from langchain_community.vectorstores import Chroma
class VectorMemory: def __init__(self, collection_name: str = "memory"): self.embeddings = OpenAIEmbeddings() self.vectorstore = Chroma( collection_name=collection_name, embedding_function=self.embeddings )
def add_interaction(self, human: str, assistant: str, metadata: dict = None): """Store a conversation turn.""" text = f"Human: {human}\nAssistant: {assistant}" self.vectorstore.add_texts( texts=[text], metadatas=[metadata or {}] )
def get_relevant(self, query: str, k: int = 3) -> list[str]: """Retrieve relevant past interactions.""" docs = self.vectorstore.similarity_search(query, k=k) return [doc.page_content for doc in docs]
def get_context(self, current_query: str) -> str: """Get memory context for prompt.""" relevant = self.get_relevant(current_query) if not relevant: return "" return "Relevant past interactions:\n" + "\n---\n".join(relevant)
# Usage memory = VectorMemory() memory.add_interaction( "What's the capital of France?", "The capital of France is Paris." )
# Later context = memory.get_context("Tell me about French cities") # Returns relevant past interaction about Paris

from langchain_openai import ChatOpenAI

class EntityMemory:
    def __init__(self, llm):
        self.llm = llm
        self.entities = {}

    def extract_entities(self, text: str) -> dict:
        """Extract entities from text."""
        prompt = f"""Extract named entities from this text.
        Return as JSON: {{"entity_name": "entity_info"}}

        Text: {text}
        """
        response = self.llm.invoke(prompt)
        return parse_json(response.content)

    def update(self, text: str):
        """Update entity store with new information."""
        new_entities = self.extract_entities(text)
        for name, info in new_entities.items():
            if name in self.entities:
                # Merge information
                self.entities[name] = self._merge(self.entities[name], info)
            else:
                self.entities[name] = info

    def get_context(self, entities: list[str]) -> str:
        """Get context for specific entities."""
        relevant = {k: v for k, v in self.entities.items() if k in entities}
        return f"Known entities: {relevant}"

def select_memory_type(conversation_length: int, focus: str) -> str:
    """Select appropriate memory type."""

    # Short conversation
    if conversation_length < 10:
        return "buffer"

    # Entity-focused
    if focus == "entities":
        return "entity"

    # Long conversation, semantic search needed
    if conversation_length > 50:
        return "vector"

    # Long conversation, sequential
    return "summary"

from langgraph.graph import StateGraph, END

def process_node(state: WorkflowState) -> WorkflowState:
    """Process the input."""
    result = f"Processed: {state['input']}"
    return {
        "output": result,
        "messages": [f"Processed input: {state['input']}"]
    }

def validate_node(state: WorkflowState) -> WorkflowState:
    """Validate the output."""
    if "error" in state["output"].lower():
        return {"error": "Validation failed"}
    return {"messages": ["Validation passed"]}

def finalize_node(state: WorkflowState) -> WorkflowState:
    """Finalize the workflow."""
    return {"messages": ["Workflow complete"]}

from langgraph.graph import StateGraph, END

class SafeState(TypedDict):
    input: str
    output: str
    error: str | None

def safe_node(state: SafeState) -> SafeState:
    try:
        result = risky_operation(state["input"])
        return {"output": result}
    except Exception as e:
        return {"error": str(e)}

def error_handler(state: SafeState) -> SafeState:
    """Handle errors gracefully."""
    return {"output": f"Error occurred: {state['error']}"}

def route_on_error(state: SafeState) -> str:
    if state.get("error"):
        return "error_handler"
    return "next_node"

graph = StateGraph(SafeState)
graph.add_node("risky", safe_node)
graph.add_node("error_handler", error_handler)
graph.add_node("next_node", next_node)

graph.add_conditional_edges("risky", route_on_error)

from langchain_community.chat_message_histories import RedisChatMessageHistory from langchain_core.runnables.history import RunnableWithMessageHistory
def get_session_history(session_id: str): # Use unique session_id per user — never share across users return RedisChatMessageHistory( session_id=session_id, url="redis://localhost:6379", ttl=3600 # expire after 1 hour of inactivity )
chain_with_memory = RunnableWithMessageHistory( chain, get_session_history, input_messages_key="input", history_messages_key="history" )
